// ===================================================
// WF-11 Step 1: D-3, D-1 대상 날짜 계산 (KST 기준)
// today+3 = D-3 리마인더 대상, today+1 = D-1 리마인더 대상
// ===================================================

const now = new Date();
// KST 보정 (+9시간)
const kst = new Date(now.getTime() + 9 * 60 * 60 * 1000);

const pad = (n) => String(n).padStart(2, '0');

function addDays(base, days) {
  const d = new Date(base.getTime());
  d.setDate(d.getDate() + days);
  return d.getFullYear() + '-' + pad(d.getMonth() + 1) + '-' + pad(d.getDate());
}

const d3Date = addDays(kst, 3);
const d1Date = addDays(kst, 1);
const todayStr = kst.getFullYear() + '-' + pad(kst.getMonth() + 1) + '-' + pad(kst.getDate());

return [{
  json: {
    d3Date,
    d1Date,
    todayStr
  }
}];

// ===================================================
// WF-11 Step 2: 대상 목록 파싱 + 중복 발송 필터링
// student_email_sent에 D3_SENT / D1_SENT가 이미 있으면 스킵
// ===================================================

const response = $input.first().json;
const dates = $('Calculate Target Dates').first().json;
const list = response.list || [];

if (list.length === 0) {
  return [{
    json: {
      _hasTargets: false,
      _d3Count: 0,
      _d1Count: 0,
      _items: []
    }
  }];
}

const items = [];

for (const row of list) {
  const classDate = String(row.class_date || '').substring(0, 10);
  const emailSent = String(row.student_email_sent || '');
  const studentEmail = String(row.student_email || '').trim();
  const partnerCode = String(row.partner_code || '');
  const recordId = row.Id || row.id || '';

  // 수강생 이메일이 없으면 스킵
  if (!studentEmail || studentEmail.indexOf('@') === -1) continue;

  // D-3 대상
  if (classDate === dates.d3Date) {
    if (emailSent.indexOf('D3_SENT') === -1) {
      items.push({
        ...row,
        _recordId: recordId,
        _reminderType: 'D3',
        _classDate: classDate,
        _studentEmail: studentEmail,
        _partnerCode: partnerCode,
        _currentEmailSent: emailSent
      });
    }
  }

  // D-1 대상
  if (classDate === dates.d1Date) {
    if (emailSent.indexOf('D1_SENT') === -1) {
      items.push({
        ...row,
        _recordId: recordId,
        _reminderType: 'D1',
        _classDate: classDate,
        _studentEmail: studentEmail,
        _partnerCode: partnerCode,
        _currentEmailSent: emailSent
      });
    }
  }
}

const d3Count = items.filter(i => i._reminderType === 'D3').length;
const d1Count = items.filter(i => i._reminderType === 'D1').length;

if (items.length === 0) {
  return [{
    json: {
      _hasTargets: false,
      _d3Count: 0,
      _d1Count: 0,
      _items: []
    }
  }];
}

// 개별 아이템으로 분기
return items.map(item => ({
  json: {
    ...item,
    _hasTargets: true,
    _totalD3: d3Count,
    _totalD1: d1Count
  }
}));

// WF-11 대상 없음 텔레그램 메시지
const now = new Date();
const kst = new Date(now.getTime() + 9 * 60 * 60 * 1000);
const todayStr = kst.toISOString().split('T')[0];

return [{
  json: {
    _telegramMessage: '\u2705 *리마인더 발송 (' + todayStr + ')*\n\n오늘 발송 대상이 없습니다.'
  }
}];

// ===================================================
// WF-11 Step 3: 이메일 HTML 빌드 (수강생 + 파트너)
// D-3: email-templates.md 이메일 2 디자인
// D-1: email-templates.md 이메일 3 디자인
// XSS 방지: 모든 동적 값 escapeHtml 처리
// ===================================================

const settlement = $('Filter and Parse Targets').first().json;
const classResponse = $('NocoDB Get Class').first().json;
const partnerResponse = $('NocoDB Get Partner').first().json;

function escapeHtml(str) {
  if (!str) return '';
  return String(str)
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#39;');
}

function maskName(name) {
  if (!name || name.length <= 1) return name || '';
  return name.charAt(0) + '*'.repeat(name.length - 1);
}

// 클래스 정보
const classList = classResponse.list || [];
const classData = classList.length > 0 ? classList[0] : {};
const className = escapeHtml(classData.class_name || settlement.class_name || '');
const classLocation = escapeHtml(classData.location || '추후 안내');
const materialsIncluded = escapeHtml(classData.materials_included || '');

// 파트너 정보
const partnerList = partnerResponse.list || [];
const partner = partnerList.length > 0 ? partnerList[0] : {};
const partnerName = escapeHtml(partner.partner_name || '');
const partnerEmail = String(partner.email || '').trim();
const partnerContact = escapeHtml(partner.phone || '');

// 수강생 정보
const studentName = escapeHtml(settlement.student_name || '고객');
const studentEmail = settlement._studentEmail;
const classDate = escapeHtml(settlement._classDate);
const reminderType = settlement._reminderType;
const recordId = settlement._recordId;
const currentEmailSent = settlement._currentEmailSent;
const studentCount = escapeHtml(String(settlement.student_count || settlement.participants || 1));
const maskedStudentName = escapeHtml(maskName(settlement.student_name || ''));

// 공통 헤더
const header = '<tr><td style="padding: 24px 32px; text-align: center; border-bottom: 2px solid #b89b5e;">'
  + '<span style="font-size: 22px; font-weight: 700; color: #b89b5e; letter-spacing: 2px;">PRESSCO21</span><br />'
  + '<span style="font-size: 11px; color: #999999; letter-spacing: 1px;">Forever and ever and Blooming</span>'
  + '</td></tr>';

const signature = '<tr><td style="padding: 0 32px 32px;"><p style="margin: 0; font-size: 14px; color: #b89b5e; font-weight: 600;">PRESSCO21 드림</p></td></tr>';

const footer = '<tr><td style="padding: 24px 32px; text-align: center; background-color: #faf8f3; border-top: 1px solid #e8e4db;">'
  + '<p style="margin: 0 0 8px; font-size: 12px; color: #999999;">PRESSCO21 | foreverlove.co.kr</p>'
  + '<p style="margin: 0; font-size: 11px; color: #bbbbbb;">이 메일은 PRESSCO21 클래스 예약 관련 안내 메일입니다.</p>'
  + '</td></tr>';

const wrapStart = '<!DOCTYPE html><html lang="ko"><head><meta charset="UTF-8" /><meta name="viewport" content="width=device-width, initial-scale=1.0" /></head>'
  + '<body style="margin: 0; padding: 0; background-color: #f8f6f0; font-family: Pretendard, Apple SD Gothic Neo, Malgun Gothic, sans-serif;">'
  + '<table width="100%" cellpadding="0" cellspacing="0" border="0" style="background-color: #f8f6f0;"><tr><td align="center" style="padding: 24px 16px;">'
  + '<table width="600" cellpadding="0" cellspacing="0" border="0" style="max-width: 600px; width: 100%; background-color: #ffffff; border-radius: 8px; overflow: hidden; box-shadow: 0 2px 8px rgba(0,0,0,0.06);">';

const wrapEnd = '</table></td></tr></table></body></html>';

// 준비물 블록
let preparationsBlock = '';
if (materialsIncluded) {
  preparationsBlock = '<table width="100%" cellpadding="0" cellspacing="0" border="0" style="background-color: #fef9f0; border-radius: 8px; border-left: 3px solid #b89b5e; margin-bottom: 24px;">'
    + '<tr><td style="padding: 16px 20px;">'
    + '<p style="margin: 0 0 10px; font-size: 13px; font-weight: 700; color: #b89b5e;">준비물 체크리스트</p>'
    + '<p style="margin: 0; font-size: 14px; color: #555555; line-height: 1.8;">' + materialsIncluded + '</p>'
    + '</td></tr></table>';
}

// === 수강생 이메일 HTML ===
let studentSubject, studentHtml;

if (reminderType === 'D3') {
  studentSubject = '[PRESSCO21] ' + (classData.class_name || '') + ' 수업까지 3일 남았습니다!';

  studentHtml = wrapStart + header
    + '<tr><td style="padding: 40px 32px 32px;">'
    // D-3 배지
    + '<table width="100%" cellpadding="0" cellspacing="0" border="0" style="margin-bottom: 28px;"><tr><td align="center">'
    + '<span style="display: inline-block; background-color: #b89b5e; color: #ffffff; font-size: 14px; font-weight: 700; padding: 8px 20px; border-radius: 20px; letter-spacing: 1px;">D-3</span>'
    + '</td></tr></table>'
    // 인사말
    + '<p style="margin: 0 0 20px; font-size: 15px; color: #333333; line-height: 1.7;"><strong style="color: #b89b5e;">' + studentName + '</strong>님, 안녕하세요!</p>'
    + '<p style="margin: 0 0 8px; font-size: 15px; color: #333333; line-height: 1.7;"><strong>' + className + '</strong> 수업이 3일 앞으로 다가왔어요!</p>'
    + '<p style="margin: 0 0 32px; font-size: 15px; color: #333333; line-height: 1.7;">' + partnerName + ' 선생님이 즐거운 수업을 준비하고 계세요.<br />잠시 시간을 내어 수업 정보를 다시 한번 확인해주세요.</p>'
    // 수업 정보
    + '<table width="100%" cellpadding="0" cellspacing="0" border="0" style="background-color: #faf8f3; border-radius: 8px; border: 1px solid #e8e4db; margin-bottom: 24px;">'
    + '<tr><td style="padding: 20px 24px;"><table width="100%" cellpadding="0" cellspacing="0" border="0">'
    + '<tr><td style="padding: 6px 0; font-size: 13px; color: #999999; width: 80px; vertical-align: top;">클래스</td><td style="padding: 6px 0; font-size: 14px; color: #333333; font-weight: 600;">' + className + '</td></tr>'
    + '<tr><td style="padding: 6px 0; font-size: 13px; color: #999999; vertical-align: top;">일시</td><td style="padding: 6px 0; font-size: 14px; color: #333333; font-weight: 600;">' + classDate + '</td></tr>'
    + '<tr><td style="padding: 6px 0; font-size: 13px; color: #999999; vertical-align: top;">장소</td><td style="padding: 6px 0; font-size: 14px; color: #333333;">' + classLocation + '</td></tr>'
    + '</table></td></tr></table>'
    + preparationsBlock
    + (partnerContact ? '<table width="100%" cellpadding="0" cellspacing="0" border="0" style="margin-bottom: 32px;"><tr><td style="padding: 12px 20px; background-color: #f5f5f5; border-radius: 8px;"><p style="margin: 0; font-size: 13px; color: #888888; line-height: 1.6;">수업 관련 문의는 ' + partnerName + ' 선생님(' + partnerContact + ')에게 직접 연락하셔도 됩니다.</p></td></tr></table>' : '')
    + '<p style="margin: 0; font-size: 15px; color: #333333; line-height: 1.7;">3일 뒤, 꽃과 함께하는 즐거운 시간을 기대해주세요!</p>'
    + '</td></tr>' + signature + footer + wrapEnd;

} else {
  // D-1
  studentSubject = '[PRESSCO21] 내일이 수업날입니다! 준비되셨나요?';

  studentHtml = wrapStart + header
    + '<tr><td style="padding: 40px 32px 32px;">'
    // D-1 배지 (오렌지 톤)
    + '<table width="100%" cellpadding="0" cellspacing="0" border="0" style="margin-bottom: 28px;"><tr><td align="center">'
    + '<span style="display: inline-block; background-color: #c8785e; color: #ffffff; font-size: 14px; font-weight: 700; padding: 8px 20px; border-radius: 20px; letter-spacing: 1px;">D-1</span>'
    + '</td></tr></table>'
    + '<p style="margin: 0 0 20px; font-size: 15px; color: #333333; line-height: 1.7;"><strong style="color: #b89b5e;">' + studentName + '</strong>님, 안녕하세요!</p>'
    + '<p style="margin: 0 0 8px; font-size: 16px; color: #333333; line-height: 1.7; font-weight: 600;">내일이 바로 수업날이에요!</p>'
    + '<p style="margin: 0 0 32px; font-size: 15px; color: #333333; line-height: 1.7;"><strong>' + partnerName + '</strong> 선생님이 내일 기다리고 계실 거예요.<br />마지막으로 준비 사항을 확인해주세요.</p>'
    // 내일 체크리스트
    + '<table width="100%" cellpadding="0" cellspacing="0" border="0" style="background-color: #fef9f0; border-radius: 8px; border-left: 3px solid #b89b5e; margin-bottom: 24px;">'
    + '<tr><td style="padding: 20px 20px;">'
    + '<p style="margin: 0 0 12px; font-size: 14px; font-weight: 700; color: #b89b5e;">내일 준비 체크리스트</p>'
    + '<table width="100%" cellpadding="0" cellspacing="0" border="0">'
    + '<tr><td style="padding: 4px 0; font-size: 14px; color: #555555; line-height: 1.6;">&#9744; 수업 시간: <strong>' + classDate + '</strong></td></tr>'
    + '<tr><td style="padding: 4px 0; font-size: 14px; color: #555555; line-height: 1.6;">&#9744; 수업 장소: <strong>' + classLocation + '</strong></td></tr>'
    + (materialsIncluded ? '<tr><td style="padding: 4px 0; font-size: 14px; color: #555555; line-height: 1.6;">&#9744; 준비물: ' + materialsIncluded + '</td></tr>' : '')
    + '</table></td></tr></table>'
    // 오시는 길
    + '<table width="100%" cellpadding="0" cellspacing="0" border="0" style="margin-bottom: 32px;"><tr><td style="padding: 12px 20px; background-color: #f5f5f5; border-radius: 8px;">'
    + '<p style="margin: 0; font-size: 13px; color: #888888; line-height: 1.6;">처음 방문하시는 공방이라면, 미리 오시는 길을 확인해두시면 편해요.<br />수업 10분 전까지 도착해주시면 여유롭게 시작할 수 있어요.</p>'
    + '</td></tr></table>'
    + '<p style="margin: 0 0 8px; font-size: 15px; color: #333333; line-height: 1.7;">내일, 꽃과 함께하는 아름다운 시간이 기다리고 있어요.</p>'
    + '<p style="margin: 0; font-size: 15px; color: #333333; line-height: 1.7;">편안한 마음으로 오세요!</p>'
    + '</td></tr>' + signature + footer + wrapEnd;
}

// === 파트너 리마인더 이메일 ===
const daysLabel = reminderType === 'D3' ? '3일' : '1일';
const partnerSubject = '[PRESSCO21] 수업 ' + daysLabel + ' 전 알림 - ' + (classData.class_name || '');

const partnerHtml = wrapStart + header
  + '<tr><td style="padding: 40px 32px 32px;">'
  + '<p style="margin: 0 0 20px; font-size: 15px; color: #333333; line-height: 1.7;"><strong style="color: #b89b5e;">' + partnerName + '</strong>님, 안녕하세요!</p>'
  + '<p style="margin: 0 0 32px; font-size: 15px; color: #333333; line-height: 1.7;"><strong>' + className + '</strong> 수업이 <strong>' + daysLabel + '</strong> 남았습니다.</p>'
  + '<table width="100%" cellpadding="0" cellspacing="0" border="0" style="background-color: #faf8f3; border-radius: 8px; border: 1px solid #e8e4db; margin-bottom: 24px;">'
  + '<tr><td style="padding: 20px 24px;"><table width="100%" cellpadding="0" cellspacing="0" border="0">'
  + '<tr><td style="padding: 6px 0; font-size: 13px; color: #999999; width: 90px;">일시</td><td style="padding: 6px 0; font-size: 14px; color: #333333; font-weight: 600;">' + classDate + '</td></tr>'
  + '<tr><td style="padding: 6px 0; font-size: 13px; color: #999999;">예약 인원</td><td style="padding: 6px 0; font-size: 14px; color: #333333;">' + studentCount + '명</td></tr>'
  + '<tr><td style="padding: 6px 0; font-size: 13px; color: #999999;">수강생</td><td style="padding: 6px 0; font-size: 14px; color: #333333;">' + maskedStudentName + '</td></tr>'
  + '</table></td></tr></table>'
  + '<p style="margin: 0; font-size: 13px; color: #888888;">* 파트너 대시보드에서 상세 예약 현황을 확인할 수 있습니다.</p>'
  + '</td></tr>' + signature + footer + wrapEnd;

return [{
  json: {
    ...settlement,
    _studentEmailData: { to: studentEmail, subject: studentSubject, html: studentHtml },
    _partnerEmailData: { to: partnerEmail, subject: partnerSubject, html: partnerHtml },
    _hasPartnerEmail: !!(partnerEmail && partnerEmail.indexOf('@') !== -1),
    _reminderType: reminderType,
    _recordId: recordId,
    _currentEmailSent: currentEmailSent,
    _newEmailSent: currentEmailSent + (currentEmailSent ? ',' : '') + reminderType + '_SENT'
  }
}];

// WF-11 결과 집계 + 텔레그램
const allItems = $('Filter and Parse Targets').all();
const d3Count = allItems.filter(i => i.json._reminderType === 'D3').length;
const d1Count = allItems.filter(i => i.json._reminderType === 'D1').length;

const now = new Date();
const kst = new Date(now.getTime() + 9 * 60 * 60 * 1000);
const todayStr = kst.toISOString().split('T')[0];

const message = '\u2709\uFE0F *리마인더 발송 완료 (' + todayStr + ')*\n\n'
  + 'D-3: ' + d3Count + '건\n'
  + 'D-1: ' + d1Count + '건\n'
  + '총: ' + (d3Count + d1Count) + '건 발송';

return [{
  json: {
    _telegramMessage: message
  }
}];
